css:
.wrapper {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  container-type: inline-size;
  height: 100%;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', sans-serif);
  font-variant-numeric: tabular-nums;
}

/* ---------- Chart card (calm dark surface; neon glow only on hover/active) ---------- */
.wrapper .rrm-card {
  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 260px;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px 18px;
  box-sizing: border-box;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: border-color .15s ease, box-shadow .15s ease;
}
.wrapper .rrm-card:hover,
.wrapper .rrm-card:focus-within {
  border-color: color-mix(in srgb, var(--accent) 35%, var(--line));
  box-shadow:
    0 1px 0 rgba(255,255,255,.03) inset,
    0 6px 18px rgba(0,0,0,.5),
    0 0 24px -10px color-mix(in srgb, var(--accent) 55%, transparent);
}

/* ---------- Header: eyebrow (accent dot) · title · units sub ---------- */
.wrapper .rrm-head {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-bottom: 14px;
}
.wrapper .rrm-eyebrow {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  margin: 0;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--color-gray-700, #C2C2CC);
}
.wrapper .rrm-eyebrow::before {
  content: "";
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow: 0 0 10px -1px color-mix(in srgb, var(--accent) 70%, transparent);
  flex: none;
}
.wrapper .rrm-title {
  margin: 0;
  font: 800 14px/1.2 var(--font-stack-primary, 'Inter', system-ui);
  letter-spacing: -0.01em;
  color: var(--ink);
}
.wrapper .rrm-sub {
  margin: 0;
  font: 500 11px/1.35 var(--font-stack-primary, 'Inter', system-ui);
  color: var(--muted);
}

/* ---------- Chart canvas (ECharts mounts here; series styling lives in the chart options) ---------- */
.wrapper .rrm-canvas {
  flex: 1;
  width: 100%;
  min-height: 220px;
}

@media (prefers-reduced-motion: reduce) {
  .wrapper .rrm-card { transition: none; }
}

/* ---------- Responsive (CSS container queries, scoped to the block's own width) ---------- */
/* The block sizes to its own grid cell, not the viewport, so collapse against the
   wrapper's inline size. This is a single chart card: there is no KPI grid, data table,
   or filter bar to collapse here, and no fixed-size tap target. The chart-card contract
   from design.md §9 is: keep the canvas min-height floor when a side-by-side pair stacks
   to one column, and never let the block force horizontal page scroll. */
.wrapper .rrm-card,
.wrapper .rrm-head,
.wrapper .rrm-canvas {
  min-width: 0;
}
.wrapper .rrm-title,
.wrapper .rrm-sub {
  overflow-wrap: anywhere;
}
/* Canvas keeps its 220px floor at every width so a stacked pair never collapses the
   chart to zero height; clip to the box so chart paint can't push the block past its
   cell and trigger horizontal page scroll. (Edge tooltips need ECharts confine:true —
   a JS concern, flagged to the builder/debugger; not editable here.) */
.wrapper .rrm-canvas {
  max-width: 100%;
  min-height: 220px;
  overflow: hidden;
}

/* Chart-pair stack point: when a side-by-side pair collapses to a single column the
   cell narrows past ~720px. Tighten chrome but preserve the 220px canvas floor. */
@container (max-width: 720px) {
  .wrapper .rrm-card { padding: 14px; }
  .wrapper .rrm-head { margin-bottom: 10px; }
  .wrapper .rrm-canvas { min-height: 220px; }
}

/* Phone-narrow cell: trim padding further; canvas keeps its 220px min-height. */
@container (max-width: 480px) {
  .wrapper .rrm-card { padding: 12px; }
  .wrapper .rrm-head { margin-bottom: 8px; gap: 2px; }
  .wrapper .rrm-canvas { min-height: 220px; }
}
